/**
 * WSStation Amplituhedron wire test — Leg 4 Gap A (Agent A).
 *
 * Covers the two new optional IStation methods on WSStation:
 *   - amplituhedronReplay(): HTTP POST /amplituhedron/replay
 *       - 200 + JSON envelope → `{ hit: true, tailResidual: Float32Array }`
 *       - 204 No Content      → `{ hit: false }`
 *   - amplituhedronCapture(): HTTP POST /amplituhedron/capture (best-effort)
 *
 * These methods are HTTP-only by design — the worker's amplituhedron admin
 * endpoints live on the same base URL as the WS /flow upgrade target but do
 * NOT use the WebSocket (AMPLITUHEDRON_PLAN.md §4). The test stubs
 * `globalThis.fetch` so no real socket or HTTP server is needed.
 */

import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';

import {
  AMPLITUHEDRON_CONTENT_TYPE,
  encodeReplayResponse,
  decodeCaptureRequest,
} from '../amplituhedron-wire';
import { WSStation } from '../station-ws';

const BASE_URL = 'http://station.test';

function makeStation(): WSStation {
  return new WSStation({
    endpoint: BASE_URL,
    startLayer: 0,
    endLayer: 4,
    role: 'entry',
    phase: 'split-a',
  });
}

interface FetchCall {
  url: string;
  init: RequestInit;
}

function installFetchStub(handler: (call: FetchCall) => Response): FetchCall[] {
  const calls: FetchCall[] = [];
  vi.stubGlobal(
    'fetch',
    vi.fn(async (url: string, init: RequestInit) => {
      const call: FetchCall = { url, init };
      calls.push(call);
      return handler(call);
    }),
  );
  return calls;
}

describe('WSStation amplituhedron wire', () => {
  afterEach(() => {
    vi.unstubAllGlobals();
  });

  describe('amplituhedronReplay', () => {
    it('returns { hit: true, tailResidual, prefixResidual } on 200 + bitwise body', async () => {
      const tail = [0.25, -0.5, 0.75, 1.0];
      const tailF32 = new Float32Array(tail);
      const prefix = [10, 11, 12, 13, 14, 15, 16, 17];
      const prefixF32 = new Float32Array(prefix);
      const replayBytes = encodeReplayResponse({
        hit: true,
        tailLen: tailF32.length,
        kvSlabLen: 0,
        tailResidual: tailF32,
        prefixResidualLen: prefixF32.length,
        prefixResidual: prefixF32,
      });
      const calls = installFetchStub(() =>
        new Response(
          replayBytes.buffer.slice(
            replayBytes.byteOffset,
            replayBytes.byteOffset + replayBytes.byteLength,
          ) as ArrayBuffer,
          {
            status: 200,
            headers: { 'content-type': AMPLITUHEDRON_CONTENT_TYPE },
          },
        ),
      );

      // Synthetic decimal u64 fixture — codec requires decimal u64 strings.
      const station = makeStation();
      const result = await station.amplituhedronReplay({
        prefixHash: '3735928559',
        prefixLen: 17,
        layerLo: 0,
        layerHi: 4,
      });

      expect(result.hit).toBe(true);
      expect(result.tailResidual).toBeInstanceOf(Float32Array);
      // Compare via Array.from to dodge Float32Array precision quirks
      // (these are exact-representable values so this is a strict check).
      expect(Array.from(result.tailResidual!)).toEqual(tail);
      expect(result.prefixResidual).toBeInstanceOf(Float32Array);
      expect(Array.from(result.prefixResidual!)).toEqual(prefix);
      expect(result.tailFingerprint).toMatch(/^[0-9a-f]{16}$/);
      expect(result.prefixFingerprint).toMatch(/^[0-9a-f]{16}$/);

      // Assert the wire shape matches AMPLITUHEDRON_PLAN.md §4.
      expect(calls).toHaveLength(1);
      expect(calls[0]!.url).toBe(`${BASE_URL}/amplituhedron/replay`);
      expect(calls[0]!.init.method).toBe('POST');
      const sentBody = JSON.parse(calls[0]!.init.body as string) as Record<
        string,
        unknown
      >;
      expect(sentBody).toEqual({
        prefix_hash: '3735928559',
        prefix_len: 17,
        layer_lo: 0,
        layer_hi: 4,
      });
    });

    it('returns { hit: false } on 204 No Content (miss)', async () => {
      installFetchStub(() => new Response(null, { status: 204 }));

      const station = makeStation();
      const result = await station.amplituhedronReplay({
        prefixHash: '3735928559',
        prefixLen: 9,
        layerLo: 0,
        layerHi: 4,
      });

      expect(result).toEqual({ hit: false });
      expect(result.tailResidual).toBeUndefined();
    });

    it('returns { hit: false } defensively on network error', async () => {
      vi.stubGlobal(
        'fetch',
        vi.fn(async () => {
          throw new Error('connection refused');
        }),
      );

      const station = makeStation();
      const result = await station.amplituhedronReplay({
        prefixHash: '1',
        prefixLen: 1,
        layerLo: 0,
        layerHi: 4,
      });

      expect(result).toEqual({ hit: false });
    });
  });

  describe('amplituhedronCapture', () => {
    it('POSTs bitwise envelope to /amplituhedron/capture with tail_residual', async () => {
      const calls = installFetchStub(
        () => new Response(JSON.stringify({ captured: true }), { status: 200 }),
      );

      const station = makeStation();
      const tail = new Float32Array([1.0, 2.0, 3.0, 4.0]);
      await station.amplituhedronCapture({
        prefixHash: '3405691582',
        prefixLen: 13,
        layerLo: 0,
        layerHi: 4,
        tailResidual: tail,
      });

      expect(calls).toHaveLength(1);
      expect(calls[0]!.url).toBe(`${BASE_URL}/amplituhedron/capture`);
      expect(calls[0]!.init.method).toBe('POST');
      const sentBody = calls[0]!.init.body as Uint8Array | ArrayBuffer;
      const bytes =
        sentBody instanceof Uint8Array
          ? sentBody
          : new Uint8Array(sentBody);
      const decoded = decodeCaptureRequest(bytes);
      expect(decoded.prefixHash).toBe('3405691582');
      expect(decoded.prefixLen).toBe(13);
      expect(decoded.layerLo).toBe(0);
      expect(decoded.layerHi).toBe(4);
      expect(Array.from(decoded.tailResidual ?? new Float32Array())).toEqual([
        1.0, 2.0, 3.0, 4.0,
      ]);
    });

    it('never throws on network error (fire-and-forget contract)', async () => {
      vi.stubGlobal(
        'fetch',
        vi.fn(async () => {
          throw new Error('upstream gone');
        }),
      );

      const station = makeStation();
      await expect(
        station.amplituhedronCapture({
          prefixHash: '1',
          prefixLen: 1,
          layerLo: 0,
          layerHi: 4,
          tailResidual: new Float32Array([0]),
        }),
      ).resolves.toBeUndefined();
    });
  });

  describe('amplituhedron headers', () => {
    it('replay sets Accept and capture sets Content-Type to application/x-bitwise-residual', async () => {
      // Replay leg: Accept must announce the bitwise wire.
      const replayCalls = installFetchStub(
        () => new Response(null, { status: 204 }),
      );
      const replayStation = makeStation();
      await replayStation.amplituhedronReplay({
        prefixHash: '8888888888',
        prefixLen: 1,
        layerLo: 0,
        layerHi: 4,
      });
      expect(replayCalls).toHaveLength(1);
      const replayHeaders =
        (replayCalls[0]!.init.headers as Record<string, string>) ?? {};
      expect(replayHeaders['accept']).toBe(AMPLITUHEDRON_CONTENT_TYPE);

      vi.unstubAllGlobals();

      // Capture leg: Content-Type must declare the bitwise wire.
      const captureCalls = installFetchStub(
        () => new Response('', { status: 200 }),
      );
      const captureStation = makeStation();
      await captureStation.amplituhedronCapture({
        prefixHash: '8888888888',
        prefixLen: 1,
        layerLo: 0,
        layerHi: 4,
        tailResidual: new Float32Array([1, 2]),
      });
      expect(captureCalls).toHaveLength(1);
      const captureHeaders =
        (captureCalls[0]!.init.headers as Record<string, string>) ?? {};
      expect(captureHeaders['content-type']).toBe(AMPLITUHEDRON_CONTENT_TYPE);
    });
  });
});
